import{_ as e,o as r,c as t,a2 as i}from"./chunks/framework.DnrXFDHb.js";const d=JSON.parse('{"title":"G10: 關鍵合作夥伴與Tier1客戶 - 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/4967_十銓/20260428/G10_關鍵合作夥伴與Tier1客戶.md","filePath":"審計報告庫/經營審計/4967_十銓/20260428/G10_關鍵合作夥伴與Tier1客戶.md"}'),l={name:"審計報告庫/經營審計/4967_十銓/20260428/G10_關鍵合作夥伴與Tier1客戶.md"};function o(n,a,s,h,c,g){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="g10-關鍵合作夥伴與tier1客戶-投資研究員審計報告" tabindex="-1">G10: 關鍵合作夥伴與Tier1客戶 - 投資研究員審計報告 <a class="header-anchor" href="#g10-關鍵合作夥伴與tier1客戶-投資研究員審計報告" aria-label="Permalink to &quot;G10: 關鍵合作夥伴與Tier1客戶 - 投資研究員審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的投資洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司是否擁有具備國際指標性的關鍵合作夥伴或 Tier1 客戶？這類關係的穩定度與進入壁壘為何？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：十銓上游與三星、SK海力士、南亞科有數十年穩定配額，下游客戶集中度高——兩大客戶佔40.6%（合計82.86億）。B2B佔比跳升至47.58%，客戶結構重建中，但認證深度仍待觀察。</li><li><strong>風險評級</strong>：高</li><li><strong>數據時效</strong>：根據截至2026年最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>： <ul><li>兩大客戶2025年合計貢獻82.86億（佔40.6%），集中度偏高</li><li>透過關係人TR及Newegg銷售至北美終端市場</li><li>與三星/SK海力士/南亞科有數十年合作關係，每月固定配額</li><li>2026Q1 B2B營收佔比47.58%，企業級客戶結構正在重建</li></ul></li><li><strong>診斷見解</strong>：十銓客戶關係呈現「雙軌結構」——上游原廠關係穩固（數十年交易+固定配額），但下游客戶集中度偏高。2025年兩大客戶佔40.6%，任一客戶訂單波動都將對營收產生顯著衝擊。B2B佔比跳升是正向訊號，但新客戶的認證深度仍待觀察。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="上游原廠關係——料源穩定性" tabindex="-1">上游原廠關係——料源穩定性 <a class="header-anchor" href="#上游原廠關係——料源穩定性" aria-label="Permalink to &quot;上游原廠關係——料源穩定性&quot;">​</a></h3><ul><li><strong>核心重點</strong>：十銓與三星、SK海力士、南亞科技維持數十年交易，確保每月固定配額。在DRAM供應緊張時期（如2026Q1），此配額機制使十銓相較小型模組廠更具供貨穩定性。</li><li><strong>深度見解</strong>：原廠配額的「護城河」有時間價值——漲價週期中穩定料源=穩定出貨=營收成長；但跌價週期中，原廠可能優先削減模組廠配額以保自身利潤，十銓的供貨穩定性反而成為壓力來源。</li></ul><h3 id="下游客戶結構——集中度風險" tabindex="-1">下游客戶結構——集中度風險 <a class="header-anchor" href="#下游客戶結構——集中度風險" aria-label="Permalink to &quot;下游客戶結構——集中度風險&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2025年兩大客戶甲公司貢獻51.38億（25.2%）、乙公司31.48億（15.4%），合計40.6%。財報未揭露客戶名稱，透過關係人TR及Newegg銷售至北美市場。2026Q1 B2B營收47.58%，企業級客戶正在放量。</li><li><strong>深度見解</strong>：客戶集中度40.6%屬「中高」水平。風險：(1)若甲/乙公司任一調整採購策略，營收面臨10%-25%衝擊；(2)模組規格標準化，同業可透過價格競爭切入；(3)B2B新客戶認證週期長（6-12月），短期難以分散集中度風險。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：客戶集中度「雙面刃」——40.6%營收集中在兩大客戶，中期面臨結構性風險。若甲公司（佔25.2%）採購需求下降20%，十銓營收將蒸發10.27億（約5%），且短期難以補回。</li><li><strong>空頭風險二</strong>：原廠配額「被動依賴」——料源穩定性取決於原廠配額政策，非自身優勢。在DRAM供應過剩時，原廠可能優先保障大型模組廠（如金士頓），十銓配額被削減，導致「有單無貨」風險。最極端情境：配額削減30%+客戶訂單下降15%→營收蒸發約20%。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>年報</strong>: OK — 2025_Q4_4967_合併.pdf（兩大客戶佔比51.38億+31.48億、關係人交易Newegg揭露）</li><li><strong>年報</strong>: OK — 2024_Q4_4967_合併.pdf（甲公司87.67億佔43.9%、美國子公司設立）</li><li><strong>法說會/新聞</strong>: OK — B2B營收佔比47.58%（teamgroupinc.com公告）、與三星/SK海力士/南亞科合作（新聞報導）</li><li><strong>關鍵核對碼</strong>: 「甲公司113年度貢獻營收87.67億元（43.9%）」（2024年報）、「透過關係人TR銷售予Newegg」（2025年報附註）</li></ul><hr><p><strong>報告寫入路徑</strong>：/Users/kaipro/.openclaw/skills/NEW_Deep32Q/審計報告庫/4967_十銓/20260428/經營組/G10_關鍵合作夥伴與Tier1客戶.md <strong>審計身分</strong>：投資研究員 (finance-investment-researcher) | Deep32Q L3 <strong>數據時效</strong>：截至2026年4月28日最新公開數據</p>',19)])])}const u=e(l,[["render",o]]);export{d as __pageData,u as default};
